oxy_webhelp_navlinks = {"tocId-d27248e18939":{"topics":[{"title":"Rubrik backup components for Azure SQL DB","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Azure SQL Databases by taking Rubrik backups that use         several key components: Rubrik Exocompute for data processing, the Cloud Storage Layer for         efficient storage, and snapshot immutability for cyber resilience. These backups offer         significant advantages, including a logical air gap and flexible recovery         options.<\/p>","href":"saas\/azr_sql_db_rbk_backup_components.html","attributes":{"data-id":"azr_sql_db_rbk_backup_components"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_rbk_backup_components-d27248e18940","topics":[]},{"title":"Supported datatypes for Azure SQL DB Rubrik backups","shortdesc":"<p class=\"shortdesc\">Information about the datatypes that <span class=\"ph\">RSC<\/span> supports for the Azure SQL         Database Rubrik backups.<\/p>","href":"saas\/azr_sql_db_supp_datatypes_rbk_backup.html","attributes":{"data-id":"azr_sql_db_supp_datatypes_rbk_backup"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_supp_datatypes_rbk_backup-d27248e18953","topics":[]},{"title":"Support for Azure SQL TDE with customer-managed keys","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> supports the backup and recovery of Azure SQL Databases encrypted         using Transparent Data Encryption with Customer-Managed Keys.<\/p>","href":"saas\/azure_sql_tde_support.html","attributes":{"data-id":"azure_sql_tde_support"},"menu":{"hasChildren":false},"tocID":"azure_sql_tde_support-d27248e18967","topics":[]}]}};